const from = ($json.body?.From || $json.From || '').toString();
const to = ($json.body?.To || $json.To || '').toString();
const text = ($json.body?.Body || $json.Body || '').toString().trim();
const messageSid = ($json.body?.MessageSid || $json.MessageSid || '').toString();
const profileName = ($json.body?.ProfileName || $json.ProfileName || '').toString();

const bookingIntent = /(book|appointment|schedule|tomorrow|today|monday|tuesday|wednesday|thursday|friday|saturday|am|pm|oil|brake|tires?|diagnostic|repair|service)/i.test(text);

let serviceType = 'general service';
if (/oil/i.test(text)) serviceType = 'oil change';
else if (/brake/i.test(text)) serviceType = 'brake service';
else if (/tire|tyre/i.test(text)) serviceType = 'tire service';
else if (/diagnostic/i.test(text)) serviceType = 'diagnostic';
else if (/battery/i.test(text)) serviceType = 'battery service';
else if (/engine/i.test(text)) serviceType = 'engine repair';

const currentDate = new Date().toISOString();

const systemPrompt = `You are AutoShop AI, an SMS booking assistant for an auto repair shop.\nYour job:\n1. Reply like a real service advisor by SMS.\n2. Be concise, helpful, and natural.\n3. If the customer wants to book, collect missing info.\n4. Extract booking info when present.\n5. Never use markdown.\n6. Return STRICT JSON only.\n\nBusiness context:\n- Shop name: AutoShop AI\n- Channel: SMS\n- Goal: convert inbound SMS into appointment booking\n- Timezone: America/Chicago\n- Current timestamp: ${currentDate}\n\nReturn JSON exactly in this shape:\n{\n  "reply_text": "string",\n  "booking_intent": true,\n  "customer_name": "string",\n  "service_type": "string",\n  "requested_time_text": "string",\n  "needs_more_info": true,\n  "calendar_summary": "string",\n  "calendar_description": "string"\n}\n\nRules:\n- booking_intent = true if the person appears to want service or scheduling.\n- If date/time is unclear, ask for it in reply_text and set needs_more_info = true.\n- If service type is unclear, ask for it.\n- Keep reply_text short enough for SMS.\n- calendar_summary should be short.\n- calendar_description should include the original SMS.`;

const userPrompt = `Inbound customer SMS:\nFrom: ${from}\nProfile Name: ${profileName}\nMessage: ${text}\n\nHeuristic booking intent: ${bookingIntent}\nHeuristic service type: ${serviceType}`;

const openaiBody = JSON.stringify({
  model: 'gpt-4o-mini',
  temperature: 0.2,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
});

const twilioSid = $env.TWILIO_ACCOUNT_SID || '';
const twilioToken = $env.TWILIO_AUTH_TOKEN || '';
const twilioMsgSid = $env.TWILIO_MESSAGING_SERVICE_SID || '';
const openaiKey = $env.OPENAI_API_KEY || '';
const twilioAuth = 'Basic ' + Buffer.from(twilioSid + ':' + twilioToken).toString('base64');

return [{
  json: {
    from,
    to,
    body: text,
    message_sid: messageSid,
    profile_name: profileName,
    booking_intent_heuristic: bookingIntent,
    service_type_heuristic: serviceType,
    openai_system_prompt: systemPrompt,
    openai_user_prompt: userPrompt,
    openai_body: openaiBody,
    openai_bearer: 'Bearer ' + openaiKey,
    twilio_auth: twilioAuth,
    twilio_sid: twilioSid,
    twilio_msg_sid: twilioMsgSid
  }
}];

const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    reply_text: 'Thanks for contacting AutoShop AI. What service do you need and what day/time works for you?',
    booking_intent: true,
    customer_name: '',
    service_type: 'general service',
    requested_time_text: '',
    needs_more_info: true,
    calendar_summary: 'AutoShop appointment inquiry',
    calendar_description: `Raw AI parse failed. Original response: ${raw}`
  };
}

return [{
  json: {
    ...$('Prepare AI Prompt').first().json,
    ai_raw: raw,
    reply_text: parsed.reply_text || 'Thanks for contacting AutoShop AI. What service do you need and what day/time works for you?',
    booking_intent: !!parsed.booking_intent,
    customer_name: parsed.customer_name || '',
    service_type: parsed.service_type || $('Prepare AI Prompt').first().json.service_type_heuristic || 'general service',
    requested_time_text: parsed.requested_time_text || '',
    needs_more_info: parsed.needs_more_info !== undefined ? !!parsed.needs_more_info : true,
    calendar_summary: parsed.calendar_summary || 'AutoShop appointment inquiry',
    calendar_description: parsed.calendar_description || `From: ${$('Prepare AI Prompt').first().json.from}\nOriginal SMS: ${$('Prepare AI Prompt').first().json.body}`
  }
}];

const requested = ($json.requested_time_text || '').trim();

function fallbackSlot() {
  const d = new Date();
  d.setDate(d.getDate() + 1);
  d.setHours(10, 0, 0, 0);
  return d;
}

let start = new Date(requested);
if (isNaN(start.getTime())) {
  start = fallbackSlot();
}

const end = new Date(start.getTime() + 60 * 60 * 1000);

const summary = $json.calendar_summary || `AutoShop - ${$json.service_type}`;
const description = [
  `Customer phone: ${$json.from}`,
  `Profile name: ${$json.profile_name || ''}`,
  `Service type: ${$json.service_type || ''}`,
  `Requested time text: ${$json.requested_time_text || ''}`,
  `Original SMS: ${$json.body || ''}`,
  '',
  ($json.calendar_description || '')
].join('\n');

return [{
  json: {
    ...$json,
    calendar_start: start.toISOString(),
    calendar_end: end.toISOString(),
    calendar_summary_final: summary,
    calendar_description_final: description
  }
}];

const calendarNode = $input.first().json;
const base = $('Parse AI JSON').first().json;

let finalReply = base.reply_text;
let bookingStatus = 'not_attempted';

if (calendarNode.id) {
  bookingStatus = 'created';
  const start = base.calendar_start || $('Build Calendar Event').first().json.calendar_start;
  finalReply = `You’re booked for ${base.service_type}. We’ve created your appointment for ${start}. Reply STOP to cancel or text us if you need changes.`;
} else if (base.booking_intent && !base.needs_more_info) {
  bookingStatus = 'calendar_failed';
  finalReply = `We received your booking request for ${base.service_type}. Calendar sync failed, but your request was captured. We’ll confirm shortly.`;
}

return [{
  json: {
    ...base,
    booking_status: bookingStatus,
    final_reply_text: finalReply
  }
}];

const base = $input.first().json;
return [{
  json: {
    ...base,
    booking_status: 'needs_more_info_or_no_booking',
    final_reply_text: base.reply_text
  }
}];
